steps.script:
var found := false
var stack: Array = [tree.root.get_node("/root/PadHintBar")]
while not stack.is_empty():
	var nd: Node = stack.pop_back()
	for c in nd.get_children():
		if c is Label and str(c.text) == "Zoom":
			found = true
		stack.append(c)
return found

var pr = tree.root.get_node("/root/PadRouter")
pr._apply_list_focus_policy(true)
var filt = tree.current_scene.get_node("HUD_Right").find_child("UnitListFilter", true, false)
return filt.focus_mode if filt != null else -1

var filt = tree.current_scene.get_node("HUD_Right").find_child("UnitListFilter", true, false)
filt.focus_mode = Control.FOCUS_ALL
filt.grab_focus()
return tree.current_scene._is_text_input_focused()
